    func simulateUniversalLink() {
        let codes = ["SUMMER50", "WELCOME25", "SAVE30", "MEGA40"]
        let discounts = [25, 30, 40, 50]
        
        let randomCode = codes.randomElement() ?? "PROMO"
        let randomDiscount = discounts.randomElement() ?? 20
        
        if let url = URL(string: "https://myapp.com/promo?code=\(randomCode)&discount=\(randomDiscount)") {
            _ = handleUniversalLink(url: url)
        }
    }
